export function removeDuplicates<T>(arr: T[], property: keyof T): T[] {
    const uniqueMap = new Map();

    return arr.filter((item) => {
        const key = item[property];

        if (!uniqueMap.has(key)) {
            uniqueMap.set(key, true);
            return true;
        }

        return false;
    });
}