import React, { useState } from "react";
import { IAddress, ICartRes, IItem } from "../types/types";
import { isBrowser } from "../utils/utils";
import api from "../components/api";

const CART_KEY = "items";
const COUPON_KEY = "coupon";

class Cart {
  public static getItems(): IItem[] {
    const storedItems = isBrowser && window.localStorage.getItem(CART_KEY);
    return storedItems ? JSON.parse(storedItems) : [];
  }

  public static addItem(item: IItem): void {
    let currentItems = Cart.getItems();
    const prevItemIndex = currentItems.findIndex((c) => c.productId === item.productId && c.stockId === item.stockId);
    if (prevItemIndex !== -1) {
      currentItems[prevItemIndex].quantity += 1;
    } else {
      currentItems.push(item);
    }
    if (isBrowser) window.localStorage.setItem(CART_KEY, JSON.stringify(currentItems));
  }

  public static removeItem(productId: number, stockId: number): void {
    const currentItems = Cart.getItems();
    const updatedItems = currentItems.filter(function (item) {
      return item.productId !== productId || item.stockId !== stockId;
    });
    if (isBrowser) window.localStorage.setItem(CART_KEY, JSON.stringify(updatedItems));
  }

  public static updateQuantity(productId: number, stockId: number, quantity: number): void {
    const currentItems = Cart.getItems();
    const updatedItems = currentItems.map((item) => {
      if (item.productId === productId && item.stockId === stockId) {
        item.quantity = quantity;
      }
      return item;
    });
    if (isBrowser) window.localStorage.setItem(CART_KEY, JSON.stringify(updatedItems));
  }
}


export class CookieCoupon {
  public static getCoupon(): string {
    const cp = isBrowser && window.localStorage.getItem(COUPON_KEY);
    return cp || "";
  }

  public static update(cp: string): void {
    if (isBrowser) window.localStorage.setItem(COUPON_KEY, cp);
  }

  public static remove(): void {
    if (isBrowser) window.localStorage.removeItem(COUPON_KEY);
  }
}

const useCart = () => {
  const [items, setItems] = useState<IItem[]>(Cart.getItems());
  const [cartRes, setCartRes] = useState<ICartRes>();

  const addItemToCart = (item: IItem) => {
    Cart.addItem(item);
    setItems(Cart.getItems());
  };

  const removeItemFromCart = (productId: number, stockId: number) => {
    Cart.removeItem(productId, stockId);
    setItems(Cart.getItems());
  };

  const updateQuantity = (productId: number, stockId: number, quantity: number) => {
    Cart.updateQuantity(productId, stockId, quantity);
    setItems(Cart.getItems());
  };

  const updateCartResApi = (address: IAddress | null, coupon: string | null) => {
    api.post("/v1/cart", {
      buy: {
        items: items.map((i) => ({
          productId: i.productId,
          stockId: i.stockId,
          quantity: i.quantity
        })),
        coupon: coupon || null,
        address: {
          zipcode: address?.cep || null,
          state: address?.state || null,
          city: address?.city || null
        }
      }
    }).then((res) => {
      setCartRes(res.data);
    }).catch((e) => {
      console.log(e);
      alert('Houve um erro, tente mais tarde.')
    });
  }

  return {
    items, addItemToCart, removeItemFromCart, updateQuantity, cartRes, updateCartResApi
  };
};

export default useCart;